import { ApiClient } from "./api-client";
import { ConsumerGroup } from "./consumer-group";
import type { ConsumerGroupOptions, SendOptions, SendResult } from "./types";
import { isDevMode, invokeDevHandlers } from "./dev";

/**
 * A Topic represents a named channel for publishing messages in a pub/sub pattern
 */
export class Topic<T = unknown> {
  private client: ApiClient;
  private topicName: string;

  /**
   * @param client ApiClient instance to use for API calls
   * @param topicName Name of the topic to work with
   */
  constructor(client: ApiClient, topicName: string) {
    this.client = client;
    this.topicName = topicName;
  }

  /**
   * Publish a message to the topic
   * @param payload The data to publish
   * @param options Optional publish options
   * @returns `{ messageId }` — `messageId` is `null` when deferred
   * @throws {BadRequestError} When request parameters are invalid
   * @throws {UnauthorizedError} When authentication fails
   * @throws {ForbiddenError} When access is denied (environment mismatch)
   * @throws {InternalServerError} When server encounters an error
   */
  async publish(payload: T, options?: SendOptions): Promise<SendResult> {
    const result = await this.client.sendMessage<T>({
      queueName: this.topicName,
      payload,
      idempotencyKey: options?.idempotencyKey,
      retentionSeconds: options?.retentionSeconds,
      delaySeconds: options?.delaySeconds,
      headers: options?.headers,
    });

    // In development mode, automatically trigger registered callbacks after 1s
    if (result.messageId && isDevMode()) {
      invokeDevHandlers(
        this.topicName,
        result.messageId,
        this.client.getRegion(),
        options?.delaySeconds,
        options?.retentionSeconds,
      );
    }

    return { messageId: result.messageId };
  }

  /**
   * Create a consumer group for this topic
   * @param consumerGroupName Name of the consumer group
   * @param options Optional configuration for the consumer group
   * @returns A ConsumerGroup instance
   */
  consumerGroup<U = T>(
    consumerGroupName: string,
    options?: ConsumerGroupOptions<U>,
  ): ConsumerGroup<U> {
    return new ConsumerGroup<U>(
      this.client,
      this.topicName,
      consumerGroupName,
      options,
    );
  }

  /**
   * Get the topic name
   */
  get name(): string {
    return this.topicName;
  }
}
