/**
 * Core queue callback utilities for handling incoming webhook payloads
 * from Vercel triggers using the CloudEvent specification.
 *
 * This module provides the framework-agnostic core. For framework-specific
 * wrappers, see `@vercel/queue/web` and `@vercel/queue/nextjs/pages`.
 */
import { getApiClient, type QueueClient } from "./client";
import { Topic } from "./topic";
import type { Message, MessageHandler, RetryHandler } from "./types";
import type { Transport } from "./transports";

/**
 * CloudEvent specification for queue callbacks.
 *
 * Incoming webhook payloads from Vercel follow the CloudEvents v1.0 spec
 * with queue-specific data fields.
 *
 * @see https://cloudevents.io/
 */
export interface CloudEvent<T = unknown> {
  /** Event type identifier, e.g. `"com.vercel.queue.v1beta"` (structured) or `"com.vercel.queue.v2beta"` (binary) */
  type: string;
  /** Event source URI, e.g. `"/topic/my-topic/consumer/my-group"` */
  source: string;
  /** Unique event identifier */
  id: string;
  /** MIME type of the `data` field */
  datacontenttype: string;
  /** Event payload containing queue message metadata */
  data: T;
  /** ISO 8601 timestamp of when the event was produced */
  time?: string;
  /** CloudEvents specification version */
  specversion?: string;
}

/**
 * Options for configuring `handleCallback` behavior.
 */
export interface HandleCallbackOptions {
  /**
   * QueueClient instance to use for processing messages.
   * If not provided, a default client is created with OIDC authentication
   * and JsonTransport.
   */
  client?: QueueClient;

  /**
   * Time in seconds that messages will be invisible to other consumers
   * during processing. The handler will automatically extend this timeout
   * while processing.
   *
   * @default 300 (5 minutes)
   * @minimum 30
   * @maximum 3600 (1 hour)
   */
  visibilityTimeoutSeconds?: number;

  /**
   * Called when the handler throws. Return `{ afterSeconds: N }` to reschedule
   * the message for redelivery after N seconds, or return `undefined`
   * to let the error propagate normally.
   */
  retry?: RetryHandler;
}

export const CLOUD_EVENT_TYPE_V1BETA = "com.vercel.queue.v1beta";
export const CLOUD_EVENT_TYPE_V2BETA = "com.vercel.queue.v2beta";

/**
 * Routing-only callback: the SDK must fetch the message by ID.
 * Produced by v1beta structured mode and v2beta large-body mode.
 */
export type ParsedCallbackV1 = {
  queueName: string;
  consumerGroup: string;
  messageId: string;
  region?: string;
};

/**
 * Full-message callback: payload and receipt handle are inlined,
 * so the SDK can process directly without an extra fetch.
 * Produced by v2beta small-body mode.
 */
export type ParsedCallbackV2 = {
  queueName: string;
  consumerGroup: string;
  messageId: string;
  region?: string;
  receiptHandle: string;
  deliveryCount?: number;
  createdAt?: string;
  expiresAt?: string;
  contentType?: string;
  visibilityDeadline?: string;
  rawBody?: ReadableStream<Uint8Array>;
  parsedPayload?: unknown;
};

export type ParsedCallbackRequest = ParsedCallbackV1 | ParsedCallbackV2;

/**
 * Check if a topic name matches a wildcard pattern.
 * Used by dev mode for route discovery from vercel.json.
 *
 * @param topicName - The topic name to test
 * @param pattern - A wildcard pattern ending with `*`
 * @returns `true` if topicName starts with the pattern prefix
 */
export function matchesWildcardPattern(
  topicName: string,
  pattern: string,
): boolean {
  // Remove the trailing *
  const prefix = pattern.slice(0, -1);
  return topicName.startsWith(prefix);
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

/**
 * Parse and validate a v1beta structured CloudEvent body.
 *
 * @internal
 */
function parseV1StructuredBody(
  body: unknown,
  contentType: string | null,
): ParsedCallbackRequest {
  if (!contentType || !contentType.includes("application/cloudevents+json")) {
    throw new Error(
      "Invalid content type: expected 'application/cloudevents+json'",
    );
  }

  if (
    !isRecord(body) ||
    !body.type ||
    !body.source ||
    !body.id ||
    !isRecord(body.data)
  ) {
    throw new Error("Invalid CloudEvent: missing required fields");
  }

  if (body.type !== CLOUD_EVENT_TYPE_V1BETA) {
    throw new Error(
      `Invalid CloudEvent type: expected '${CLOUD_EVENT_TYPE_V1BETA}', got '${String(body.type)}'`,
    );
  }

  const { data } = body;
  const missingFields: string[] = [];
  if (!("queueName" in data)) missingFields.push("queueName");
  if (!("consumerGroup" in data)) missingFields.push("consumerGroup");
  if (!("messageId" in data)) missingFields.push("messageId");
  if (missingFields.length > 0) {
    throw new Error(
      `Missing required CloudEvent data fields: ${missingFields.join(", ")}`,
    );
  }

  return {
    queueName: String(data.queueName),
    consumerGroup: String(data.consumerGroup),
    messageId: String(data.messageId),
  };
}

type HeaderSource = Headers | Record<string, string | string[] | undefined>;

function getHeader(headers: HeaderSource, name: string): string | null {
  if (headers instanceof Headers) {
    return headers.get(name);
  }
  const value = headers[name];
  if (Array.isArray(value)) return value[0] ?? null;
  return (value as string) ?? null;
}

function parseBinaryHeaders(headers: HeaderSource): ParsedCallbackRequest {
  const ceType = getHeader(headers, "ce-type");
  if (ceType !== CLOUD_EVENT_TYPE_V2BETA) {
    throw new Error(
      `Invalid CloudEvent type: expected '${CLOUD_EVENT_TYPE_V2BETA}', got '${ceType}'`,
    );
  }

  const queueName = getHeader(headers, "ce-vqsqueuename");
  const consumerGroup = getHeader(headers, "ce-vqsconsumergroup");
  const messageId = getHeader(headers, "ce-vqsmessageid");

  const missingFields: string[] = [];
  if (!queueName) missingFields.push("ce-vqsqueuename");
  if (!consumerGroup) missingFields.push("ce-vqsconsumergroup");
  if (!messageId) missingFields.push("ce-vqsmessageid");
  if (missingFields.length > 0) {
    throw new Error(
      `Missing required CloudEvent headers: ${missingFields.join(", ")}`,
    );
  }

  const region = getHeader(headers, "ce-vqsregion") ?? undefined;

  const base = {
    queueName: queueName!,
    consumerGroup: consumerGroup!,
    messageId: messageId!,
    region,
  };

  const receiptHandle = getHeader(headers, "ce-vqsreceipthandle");
  if (!receiptHandle) {
    return base;
  }

  const result: ParsedCallbackV2 = { ...base, receiptHandle };

  const deliveryCount = getHeader(headers, "ce-vqsdeliverycount");
  if (deliveryCount) {
    result.deliveryCount = parseInt(deliveryCount, 10);
  }

  const createdAt = getHeader(headers, "ce-vqscreatedat");
  if (createdAt) {
    result.createdAt = createdAt;
  }

  const expiresAt = getHeader(headers, "ce-vqsexpiresat");
  if (expiresAt) {
    result.expiresAt = expiresAt;
  }

  const contentType = getHeader(headers, "content-type");
  if (contentType) {
    result.contentType = contentType;
  }

  const visibilityDeadline = getHeader(headers, "ce-vqsvisibilitydeadline");
  if (visibilityDeadline) {
    result.visibilityDeadline = visibilityDeadline;
  }

  return result;
}

/**
 * Parse a callback from a pre-parsed body and headers.
 *
 * For frameworks like Next.js Pages Router where the body has already been
 * parsed, use this instead of {@link parseCallback}.
 *
 * Detects the CloudEvent version from the `ce-type` header:
 * - `com.vercel.queue.v2beta`: binary content mode (metadata in headers,
 *   payload in body). For small messages, the body is attached as `parsedPayload`.
 * - Otherwise: structured content mode (v1beta, entire CloudEvent in JSON body)
 *
 * @param body - The framework-parsed request body. Type depends on Content-Type
 *   and framework configuration:
 *   - v1beta: parsed CloudEvent JSON object
 *   - v2beta: the message payload as parsed by the framework (object, Buffer, or string)
 * @param headers - HTTP headers
 * @returns Parsed callback request with routing metadata and optional payload
 */
export function parseRawCallback(
  body: unknown,
  headers: Record<string, string | string[] | undefined>,
): ParsedCallbackRequest {
  const ceType = getHeader(headers, "ce-type");

  if (ceType === CLOUD_EVENT_TYPE_V2BETA) {
    const result = parseBinaryHeaders(headers);
    if ("receiptHandle" in result) {
      result.parsedPayload = body;
    }
    return result;
  }

  return parseV1StructuredBody(body, getHeader(headers, "content-type"));
}

/**
 * Parse and validate a CloudEvent callback from a Web API `Request` object.
 *
 * Detects the CloudEvent version from the `ce-type` header:
 * - `com.vercel.queue.v2beta`: binary content mode (metadata in headers,
 *   payload in body). For v2beta, the body is attached as `rawBody` (a
 *   ReadableStream) rather than being parsed.
 * - Otherwise: structured content mode (v1beta, entire CloudEvent in JSON body)
 *
 * For frameworks that pre-parse the body (e.g. Next.js Pages Router),
 * use {@link parseRawCallback} instead.
 */
export async function parseCallback(
  request: Request,
): Promise<ParsedCallbackRequest> {
  const ceType = request.headers.get("ce-type");

  if (ceType === CLOUD_EVENT_TYPE_V2BETA) {
    const result = parseBinaryHeaders(request.headers);
    if ("receiptHandle" in result && request.body) {
      result.rawBody = request.body;
    }
    return result;
  }

  let body: unknown;
  try {
    body = await request.json();
  } catch {
    throw new Error("Failed to parse CloudEvent from request body");
  }

  const headers: Record<string, string> = {};
  request.headers.forEach((value, key) => {
    headers[key] = value;
  });

  return parseRawCallback(body, headers);
}

/**
 * Core queue callback handler. Processes the message using the provided handler.
 *
 * This is the framework-agnostic core — it takes already-parsed request data
 * and throws on errors. Framework-specific wrappers (in `@vercel/queue/web`
 * and `@vercel/queue/nextjs/pages`) compose around this function to handle
 * request parsing and response formatting.
 *
 * @param handler - Function to process the message payload and metadata
 * @param request - A {@link ParsedCallbackV1} (routing metadata only, message
 *   fetched by ID) or {@link ParsedCallbackV2} (full message inlined, no fetch).
 * @param options - Optional configuration (client, visibilityTimeoutSeconds)
 * @throws {Error} If binary mode request has a receipt handle but no payload
 * @throws {Error} If message processing fails
 *
 * @example
 * ```typescript
 * import { handleCallback, parseRawCallback } from "@vercel/queue";
 *
 * const parsed = parseRawCallback(body, headers);
 * await handleCallback(async (message, metadata) => {
 *   console.log("Processing:", message);
 * }, parsed);
 * ```
 */
export async function handleCallback<T = unknown>(
  handler: MessageHandler<T>,
  request: ParsedCallbackRequest,
  options?: HandleCallbackOptions,
): Promise<void> {
  const { queueName, consumerGroup, messageId } = request;

  if (!options?.client) {
    throw new Error("HandleCallbackOptions.client is required");
  }
  let api = getApiClient(options.client);
  if (request.region) {
    api = api.withRegion(request.region);
  }
  const topic = new Topic<T>(api, queueName);
  const cg = topic.consumerGroup(
    consumerGroup,
    options?.visibilityTimeoutSeconds !== undefined
      ? { visibilityTimeoutSeconds: options.visibilityTimeoutSeconds }
      : undefined,
  );

  if ("receiptHandle" in request) {
    const transport = api.getTransport() as Transport<T>;

    let payload: T;
    if (request.rawBody) {
      payload = await transport.deserialize(request.rawBody);
    } else if (request.parsedPayload !== undefined) {
      payload = request.parsedPayload as T;
    } else {
      throw new Error(
        "Binary mode callback with receipt handle is missing payload",
      );
    }

    const message: Message<T> = {
      messageId,
      payload,
      deliveryCount: request.deliveryCount ?? 1,
      createdAt: request.createdAt ? new Date(request.createdAt) : new Date(),
      expiresAt: request.expiresAt ? new Date(request.expiresAt) : undefined,
      contentType: request.contentType ?? transport.contentType,
      receiptHandle: request.receiptHandle,
    };

    const visibilityDeadline = request.visibilityDeadline
      ? new Date(request.visibilityDeadline)
      : undefined;

    await cg.consumeMessage(handler, message, {
      visibilityDeadline,
      retry: options?.retry,
    });
  } else {
    await cg.consume(handler, { messageId, retry: options?.retry });
  }
}
