/**
 * Development mode utilities for local queue compatibility.
 *
 * Key behaviors:
 * - Discovers queue routes from vercel.json experimentalTriggers config
 * - Registers handlers via handleCallback/handleNodeCallback at module load time
 * - On send(), invokes registered handlers directly (no HTTP round-trip)
 * - First delivery uses the production coreHandleCallback code path
 * - Re-deliveries (retries) call the handler directly for fast local iteration
 */
import * as fs from "node:fs";
import * as net from "node:net";
import * as path from "node:path";
import { minimatch } from "minimatch";
import pc from "picocolors";
import { matchesWildcardPattern } from "./callback";
import { handleCallback as coreHandleCallback } from "./callback";
import type { HandleCallbackOptions } from "./callback";
import { MessageNotFoundError } from "./types";
import type {
  MessageHandler,
  MessageMetadata,
  RetryDirective,
  RetryHandler,
} from "./types";
import type { QueueClient } from "./client";

const PREFIX = pc.cyan("[queue]");
const OK = pc.green("✓");
const FAIL = pc.red("✗");
const RETRY = pc.yellow("↻");

// ---------------------------------------------------------------------------
// Dev mode check
// ---------------------------------------------------------------------------

export function isDevMode(): boolean {
  return process.env.NODE_ENV === "development";
}

// ---------------------------------------------------------------------------
// vercel.json route mappings
// ---------------------------------------------------------------------------

const ROUTE_MAPPINGS_KEY = Symbol.for("@vercel/queue.devRouteMappings");

interface DevRouteMapping {
  filePath: string;
  topic: string;
  consumer: string;
  retryAfterSeconds?: number;
}

/**
 * Convert a file path to a consumer group name using mnemonic escapes.
 * Matches the encoding from @vercel/build-utils sanitizeConsumerName:
 *   _ → __, / → _S, . → _D, other invalid chars → _XX (hex code)
 */
function filePathToConsumerGroup(filePath: string): string {
  let result = "";
  for (const char of filePath) {
    if (char === "_") {
      result += "__";
    } else if (char === "/") {
      result += "_S";
    } else if (char === ".") {
      result += "_D";
    } else if (/[A-Za-z0-9-]/.test(char)) {
      result += char;
    } else {
      result +=
        "_" + char.charCodeAt(0).toString(16).toUpperCase().padStart(2, "0");
    }
  }
  return result;
}

function getDevRouteMappings(): DevRouteMapping[] | null {
  const g = globalThis as typeof globalThis & {
    [ROUTE_MAPPINGS_KEY]?: DevRouteMapping[] | null;
  };

  if (ROUTE_MAPPINGS_KEY in g) {
    return g[ROUTE_MAPPINGS_KEY] ?? null;
  }

  try {
    const vercelJsonPath = path.join(process.cwd(), "vercel.json");
    if (!fs.existsSync(vercelJsonPath)) {
      g[ROUTE_MAPPINGS_KEY] = null;
      return null;
    }

    const vercelJson = JSON.parse(fs.readFileSync(vercelJsonPath, "utf-8")) as {
      functions?: {
        [filePath: string]: {
          experimentalTriggers?: Array<{
            type: string;
            topic?: string;
            retryAfterSeconds?: number;
          }>;
        };
      };
    };

    if (!vercelJson.functions) {
      g[ROUTE_MAPPINGS_KEY] = null;
      return null;
    }

    const mappings: DevRouteMapping[] = [];

    for (const [filePath, config] of Object.entries(vercelJson.functions)) {
      if (!config.experimentalTriggers) continue;

      for (const trigger of config.experimentalTriggers) {
        if (!trigger.type?.startsWith("queue/") || !trigger.topic) continue;

        if (trigger.type !== "queue/v2beta") {
          console.warn(
            `${PREFIX} Unsupported trigger type "${trigger.type}" for ` +
              `topic "${trigger.topic}" in ${filePath}. ` +
              `Use "queue/v2beta" instead.`,
          );
          continue;
        }

        mappings.push({
          filePath,
          topic: trigger.topic,
          consumer: filePathToConsumerGroup(filePath),
          retryAfterSeconds: trigger.retryAfterSeconds,
        });
      }
    }

    g[ROUTE_MAPPINGS_KEY] = mappings.length > 0 ? mappings : null;
    return g[ROUTE_MAPPINGS_KEY];
  } catch (error) {
    console.warn(`${PREFIX} Failed to read vercel.json:`, error);
    g[ROUTE_MAPPINGS_KEY] = null;
    return null;
  }
}

function findMatchingRoutes(topicName: string): DevRouteMapping[] {
  const mappings = getDevRouteMappings();
  if (!mappings) return [];

  return mappings.filter((mapping) => {
    if (mapping.topic.includes("*")) {
      return matchesWildcardPattern(topicName, mapping.topic);
    }
    return mapping.topic === topicName;
  });
}

function findRetryAfterSeconds(
  topicName: string,
  consumerGroup: string,
): number | undefined {
  const routes = findMatchingRoutes(topicName);
  const route = routes.find((r) => r.consumer === consumerGroup);
  return route?.retryAfterSeconds;
}

/**
 * Strip `src/` prefix from framework directories so that e.g.
 * `src/app/api/route.ts` can match a vercel.json key `app/api/route.ts`.
 */
function stripSrcPrefix(filePath: string): string | null {
  if (/^src\/(app|pages|server)\//.test(filePath)) {
    return filePath.slice(4); // remove "src/"
  }
  return null;
}

/**
 * Test whether a source file path matches a vercel.json functions key.
 * Uses exact match + minimatch (glob), matching @vercel/build-utils behavior.
 */
function matchesFunctionsPattern(sourceFile: string, pattern: string): boolean {
  return sourceFile === pattern || minimatch(sourceFile, pattern);
}

/**
 * Find vercel.json route mappings for a given file path.
 * Tries both the literal relative path and — when the file lives under
 * `src/` — the `src/`-stripped variant so that users can write either
 * `"app/api/route.ts"` or `"src/app/api/route.ts"` in vercel.json.
 *
 * Also supports glob patterns (e.g. `"api/** /*.ts"`) via minimatch,
 * matching @vercel/build-utils getLambdaOptionsFromFunction behavior.
 */
function findMappingsForFile(absolutePath: string): DevRouteMapping[] {
  const mappings = getDevRouteMappings();
  if (!mappings) return [];

  const cwd = process.cwd();
  let relative: string;
  try {
    relative = path.relative(cwd, absolutePath);
  } catch {
    return [];
  }
  const normalized = relative.replace(/\\/g, "/");
  const stripped = stripSrcPrefix(normalized);

  return mappings.filter(
    (m) =>
      matchesFunctionsPattern(normalized, m.filePath) ||
      (stripped !== null && matchesFunctionsPattern(stripped, m.filePath)),
  );
}

// ---------------------------------------------------------------------------
// Caller file path extraction (dev-only, uses Error().stack)
// ---------------------------------------------------------------------------

function parseFrameFilePath(line: string): string | null {
  let match = line.match(/\((.+?):\d+:\d+\)/);
  if (!match) match = line.match(/at\s+(.+?):\d+:\d+/);
  if (!match) return null;
  let filePath = match[1].trim();
  if (
    filePath === "native" ||
    filePath.startsWith("node:") ||
    filePath.startsWith("internal")
  ) {
    return null;
  }
  if (filePath.startsWith("file://")) {
    try {
      filePath = new URL(filePath).pathname;
    } catch {
      return null;
    }
  }
  if (/^[a-zA-Z][a-zA-Z0-9+.-]*:\/\//.test(filePath)) {
    return null;
  }
  if (filePath.startsWith("./")) {
    filePath = filePath.slice(2);
  }
  return filePath;
}

let _sdkPackageDir: string | undefined;
function getSdkPackageDir(): string {
  if (_sdkPackageDir) return _sdkPackageDir;
  try {
    const thisDir =
      typeof __dirname !== "undefined"
        ? __dirname
        : path.dirname(new URL(import.meta.url).pathname);
    _sdkPackageDir = path.resolve(thisDir, "..");
  } catch {
    _sdkPackageDir = "";
  }
  return _sdkPackageDir;
}

/**
 * Find the file path of the first caller outside this SDK package.
 * Scans the stack frames (instead of using a fixed offset) so it works
 * regardless of how many frames the runtime inlines or collapses (e.g. Bun).
 * Handles V8 (Node.js/Deno) and JSC (Bun) stack frame formats.
 * Dev-only -- never runs in production.
 */
function extractCallerFilePath(): string | null {
  const stack = new Error().stack;
  if (!stack) return null;
  const lines = stack.split("\n").slice(1);
  const pkgDir = getSdkPackageDir();

  for (const line of lines) {
    const fp = parseFrameFilePath(line);
    if (!fp) continue;
    const absolute = path.isAbsolute(fp) ? fp : path.resolve(process.cwd(), fp);
    let realFp: string;
    try {
      realFp = fs.realpathSync(absolute);
    } catch {
      realFp = absolute;
    }
    if (pkgDir && realFp.startsWith(pkgDir)) continue;
    return realFp;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Handler registry
// ---------------------------------------------------------------------------

const HANDLER_REGISTRY_KEY = Symbol.for("@vercel/queue.devHandlerRegistry");

interface RegisteredHandler {
  consumerGroup: string;
  handler: MessageHandler;
  client: QueueClient;
  options?: { visibilityTimeoutSeconds?: number; retry?: RetryHandler };
}

type HandlerRegistry = Map<string, RegisteredHandler[]>;

function getHandlerRegistry(): HandlerRegistry {
  const g = globalThis as typeof globalThis & {
    [HANDLER_REGISTRY_KEY]?: HandlerRegistry;
  };
  if (!g[HANDLER_REGISTRY_KEY]) {
    g[HANDLER_REGISTRY_KEY] = new Map();
  }
  return g[HANDLER_REGISTRY_KEY];
}

function registerHandlerForFile(
  filePath: string,
  handler: MessageHandler,
  client: QueueClient,
  options?: { visibilityTimeoutSeconds?: number; retry?: RetryHandler },
): boolean {
  const absolutePath = path.isAbsolute(filePath)
    ? filePath
    : path.resolve(process.cwd(), filePath);
  const fileMappings = findMappingsForFile(absolutePath);
  if (fileMappings.length === 0) return false;

  const registry = getHandlerRegistry();
  for (const mapping of fileMappings) {
    const key = mapping.topic;
    const existing = registry.get(key) ?? [];
    const nextEntry: RegisteredHandler = {
      consumerGroup: mapping.consumer,
      handler,
      client,
      options,
    };
    const existingIndex = existing.findIndex(
      (e) => e.consumerGroup === mapping.consumer,
    );
    if (existingIndex >= 0) {
      // HMR can recreate handlers for the same route; keep the latest callback.
      existing[existingIndex] = nextEntry;
    } else {
      existing.push(nextEntry);
    }
    registry.set(key, existing);
  }
  return true;
}

/**
 * Register a handler for dev mode direct invocation.
 * Called from handleCallback/handleNodeCallback at module load time.
 *
 * Uses stack trace detection to find the caller's file path, then
 * matches it against vercel.json entries (exact or suffix match for
 * bundled environments).
 *
 * @internal `_testCallerPath` bypasses stack detection for tests.
 */
export function registerDevHandler(
  handler: MessageHandler,
  client: QueueClient,
  options?: { visibilityTimeoutSeconds?: number; retry?: RetryHandler },
  _testCallerPath?: string,
): void {
  const callerPath = _testCallerPath ?? extractCallerFilePath();
  if (!callerPath) {
    console.warn(
      `${PREFIX} Could not determine caller file path for handler registration.`,
    );
    return;
  }

  const registered = registerHandlerForFile(
    callerPath,
    handler,
    client,
    options,
  );

  if (!registered) {
    const allMappings = getDevRouteMappings();

    if (allMappings && allMappings.length > 0) {
      // Routes are configured but this file doesn't match any of them.
      // Don't warn here — invocation-time diagnostics in invokeDevHandlers
      // will report the real outcome after dynamic import and route priming
      // have been attempted.
      return;
    }

    const cwd = process.cwd();
    let relative: string;
    try {
      relative = path.relative(cwd, callerPath).replace(/\\/g, "/");
    } catch {
      relative = callerPath;
    }

    console.warn(
      `${PREFIX} handleCallback() in ${relative} has no matching ` +
        `experimentalTriggers in vercel.json. This handler won't receive messages.\n\n` +
        `Add a trigger to vercel.json:\n` +
        `  "${relative}": {\n` +
        `    "experimentalTriggers": [{ "type": "queue/v2beta", "topic": "your-topic" }]\n` +
        `  }`,
    );
  }
}

/**
 * Look up registered handlers for a topic. Supports wildcard topic patterns
 * from vercel.json (e.g. "user-*" matches "user-signup").
 */
function lookupHandlers(topicName: string): RegisteredHandler[] {
  const registry = getHandlerRegistry();
  const result: RegisteredHandler[] = [];

  for (const [pattern, handlers] of registry) {
    const matches = pattern.includes("*")
      ? matchesWildcardPattern(topicName, pattern)
      : pattern === topicName;
    if (matches) {
      result.push(...handlers);
    }
  }

  return result;
}

// ---------------------------------------------------------------------------
// Dev mode invocation (replaces HTTP round-trip)
// ---------------------------------------------------------------------------

const DEV_RETRY_INITIAL_DELAY_MS = 50;
const DEV_RETRY_MAX_WAIT_MS = 5000;
const DEV_RETRY_BACKOFF = 2;
const PORT_CHECK_TIMEOUT_MS = 250;
const PRIME_PORT_ENV_KEYS = [
  "PORT",
  "NEXT_PORT",
  "NEXTJS_PORT",
  "NUXT_PORT",
  "NITRO_PORT",
  "SVELTEKIT_PORT",
  "VITE_PORT",
  "DEV_PORT",
  "npm_config_port",
];
const PRIME_URL_ENV_KEYS = [
  "__NEXT_PRIVATE_ORIGIN",
  "NUXT_PUBLIC_SITE_URL",
  "URL",
];

interface ImportFailure {
  filePath: string;
  reason: string;
}

interface PrimeFailure {
  filePath: string;
  url: string;
  reason: string;
}

interface HandlerLoadDiagnostics {
  triedPorts: number[];
  listeningPorts: number[];
  unavailablePorts: number[];
  importFailures: ImportFailure[];
  primeFailures: PrimeFailure[];
}

interface EnsureHandlersLoadedOptions {
  refreshRegistered?: boolean;
}

function formatErrorReason(error: unknown): string {
  if (error instanceof Error) {
    return error.message;
  }
  return String(error);
}

function isMessageNotFoundError(error: unknown): boolean {
  if (error instanceof MessageNotFoundError) {
    return true;
  }
  if (error instanceof Error && error.name === "MessageNotFoundError") {
    return true;
  }
  return false;
}

function parsePort(value: string | undefined): number | null {
  if (!value) return null;
  const parsed = Number.parseInt(value, 10);
  if (!Number.isFinite(parsed) || parsed < 1 || parsed > 65535) return null;
  return parsed;
}

function parsePortFromUrl(value: string | undefined): number | null {
  if (!value) return null;
  try {
    const parsed = new URL(value).port;
    return parsePort(parsed);
  } catch {
    return null;
  }
}

function collectPrimePorts(): number[] {
  const result: number[] = [];
  const seen = new Set<number>();
  const add = (port: number | null) => {
    if (port && !seen.has(port)) {
      seen.add(port);
      result.push(port);
    }
  };

  for (const key of PRIME_PORT_ENV_KEYS) {
    add(parsePort(process.env[key]));
  }

  for (const key of PRIME_URL_ENV_KEYS) {
    add(parsePortFromUrl(process.env[key]));
  }

  return result;
}

function isPortListening(port: number): Promise<boolean> {
  return new Promise((resolve) => {
    const socket = net.connect({ host: "localhost", port });
    let settled = false;

    const finish = (listening: boolean) => {
      if (settled) return;
      settled = true;
      socket.destroy();
      resolve(listening);
    };

    socket.once("connect", () => finish(true));
    socket.once("error", () => finish(false));
    socket.setTimeout(PORT_CHECK_TIMEOUT_MS, () => finish(false));
  });
}

/**
 * Call coreHandleCallback with retries for eventual consistency.
 * The V1 callback path does a receiveMessageById which may throw
 * MessageNotFoundError if the message hasn't propagated yet.
 */
async function invokeWithRetry(
  handler: MessageHandler,
  request: {
    queueName: string;
    consumerGroup: string;
    messageId: string;
    region: string;
  },
  options: HandleCallbackOptions,
): Promise<void> {
  let elapsed = 0;
  let delay = DEV_RETRY_INITIAL_DELAY_MS;

  while (true) {
    try {
      await coreHandleCallback(handler, request, options);
      return;
    } catch (error) {
      if (isMessageNotFoundError(error) && elapsed < DEV_RETRY_MAX_WAIT_MS) {
        await new Promise((r) => setTimeout(r, delay));
        elapsed += delay;
        delay = Math.min(
          delay * DEV_RETRY_BACKOFF,
          DEV_RETRY_MAX_WAIT_MS - elapsed,
        );
        continue;
      }
      throw error;
    }
  }
}

/**
 * Convert a file path from vercel.json to a URL path for HTTP priming.
 * e.g., "app/api/queue/route.ts" → "/api/queue"
 */
function filePathToUrlPath(filePath: string): string {
  let urlPath = filePath
    .replace(/^src\/app\//, "/")
    .replace(/^src\/pages\//, "/")
    .replace(/^src\/server\//, "/")
    .replace(/^src\/routes\//, "/")
    .replace(/^app\//, "/")
    .replace(/^pages\//, "/")
    .replace(/^server\//, "/")
    .replace(/\/route\.(ts|mts|js|mjs|tsx|jsx)$/, "")
    .replace(/\/\+server\.(ts|mts|js|mjs|tsx|jsx)$/, "")
    .replace(/\.(ts|mts|js|mjs|tsx|jsx)$/, "");

  if (!urlPath.startsWith("/")) {
    urlPath = "/" + urlPath;
  }

  return urlPath;
}

/**
 * Attempt to load route handler modules that haven't been loaded yet.
 *
 * Strategy:
 * 1. Try dynamic import (works in tsx, plain Node, Bun, Deno)
 * 2. If still not registered, try HTTP POST to the route URL. This primes
 *    frameworks with lazy module loading (Next.js) to evaluate the route
 *    file, which triggers handleCallback() → registration.
 */
async function ensureHandlersLoaded(
  topicName: string,
  options: EnsureHandlersLoadedOptions = {},
): Promise<HandlerLoadDiagnostics> {
  const diagnostics: HandlerLoadDiagnostics = {
    triedPorts: collectPrimePorts(),
    listeningPorts: [],
    unavailablePorts: [],
    importFailures: [],
    primeFailures: [],
  };

  const matchingRoutes = findMatchingRoutes(topicName);
  if (matchingRoutes.length === 0) return diagnostics;

  const shouldRefreshRegistered = options.refreshRegistered === true;

  for (const port of diagnostics.triedPorts) {
    if (await isPortListening(port)) {
      diagnostics.listeningPorts.push(port);
    } else {
      diagnostics.unavailablePorts.push(port);
    }
  }

  for (const route of matchingRoutes) {
    const alreadyRegistered = isHandlerRegistered(topicName, route.consumer);
    if (alreadyRegistered && !shouldRefreshRegistered) {
      continue;
    }

    if (!alreadyRegistered) {
      const absolutePath = path.resolve(process.cwd(), route.filePath);
      try {
        await import(absolutePath);
      } catch (error) {
        diagnostics.importFailures.push({
          filePath: route.filePath,
          reason: formatErrorReason(error),
        });
      }

      if (isHandlerRegistered(topicName, route.consumer)) continue;
    }

    for (const port of diagnostics.listeningPorts) {
      const url = `http://localhost:${port}${filePathToUrlPath(route.filePath)}`;
      try {
        const response = await fetch(url, {
          method: "POST",
          headers: {
            "x-vercel-queue-prime": "1",
            "x-vercel-queue-prime-file": route.filePath,
          },
        });
        try {
          await response.text();
        } catch {}

        if (isHandlerRegistered(topicName, route.consumer)) {
          break;
        }

        diagnostics.primeFailures.push({
          filePath: route.filePath,
          url,
          reason:
            `HTTP ${response.status}${response.statusText ? ` ${response.statusText}` : ""}`.trim(),
        });
      } catch (error) {
        diagnostics.primeFailures.push({
          filePath: route.filePath,
          url,
          reason: formatErrorReason(error),
        });
      }
    }
  }

  return diagnostics;
}

function buildNoHandlerWarning(
  topicName: string,
  routes: DevRouteMapping[],
  diagnostics: HandlerLoadDiagnostics,
): string {
  const files = routes.map((r) => r.filePath);
  const suggestedPort =
    diagnostics.listeningPorts[0] ?? diagnostics.triedPorts[0];
  const suggestedUrls = suggestedPort
    ? routes.map(
        (r) =>
          `http://localhost:${suggestedPort}${filePathToUrlPath(r.filePath)}`,
      )
    : [];

  let portSummary: string;
  if (diagnostics.triedPorts.length === 0) {
    portSummary =
      "No local dev port detected from env. Set PORT (or NEXT_PORT/NUXT_PORT/VITE_PORT).";
  } else if (diagnostics.listeningPorts.length === 0) {
    portSummary = `Detected env ports: [${diagnostics.triedPorts.join(", ")}], but none are listening.`;
  } else {
    const unavailable =
      diagnostics.unavailablePorts.length > 0
        ? ` Not listening: [${diagnostics.unavailablePorts.join(", ")}].`
        : "";
    portSummary =
      `Detected env ports: [${diagnostics.triedPorts.join(", ")}]. ` +
      `Listening: [${diagnostics.listeningPorts.join(", ")}].` +
      unavailable;
  }

  const importSummary =
    diagnostics.importFailures.length > 0
      ? `\nImport failures: ` +
        diagnostics.importFailures
          .slice(0, 2)
          .map((f) => `${f.filePath} (${f.reason})`)
          .join("; ")
      : "";

  const primeSummary =
    diagnostics.primeFailures.length > 0
      ? `\nPrime failures: ` +
        diagnostics.primeFailures
          .slice(0, 3)
          .map((f) => `${f.url} (${f.reason})`)
          .join("; ")
      : "";

  return (
    `${PREFIX} No registered handler for topic "${topicName}". ` +
    `vercel.json maps this topic to [${files.join(", ")}] but auto-loading failed.\n` +
    `${portSummary}${importSummary}${primeSummary}\n` +
    `Ensure your dev server is running, set PORT if needed, and confirm mapped ` +
    `route files call handleCallback()/handleNodeCallback() at module scope.\n` +
    (suggestedUrls.length > 0
      ? `Try opening: ${suggestedUrls.join(" or ")}`
      : "Set PORT (or NEXT_PORT/NUXT_PORT/VITE_PORT) and try sending again.")
  );
}

function isHandlerRegistered(
  topicName: string,
  consumerGroup: string,
): boolean {
  return lookupHandlers(topicName).some(
    (h) => h.consumerGroup === consumerGroup,
  );
}

// ---------------------------------------------------------------------------
// Dev mode re-delivery (issues #5 / #6)
// ---------------------------------------------------------------------------

const DEV_REDELIVERY_MAX_DELAY_S = 10;
const DEV_REDELIVERY_DEFAULT_DELAY_S = 2;
const DEV_REDELIVERY_MAX_ATTEMPTS = 10;
const DEFAULT_RETENTION_S = 86_400; // 24 hours

interface DevRedeliveryContext {
  handler: MessageHandler;
  retry?: RetryHandler;
  payload: unknown;
  topicName: string;
  consumerGroup: string;
  messageId: string;
  region: string;
  createdAt: Date;
  retentionSeconds: number;
  deliveryCount: number;
  defaultRetryDelayS: number;
}

function scheduleDevRedelivery(
  ctx: DevRedeliveryContext,
  delayS: number,
): void {
  const cappedDelay = Math.min(Math.max(delayS, 0), DEV_REDELIVERY_MAX_DELAY_S);

  console.log(
    `${PREFIX} ${RETRY} Scheduling re-delivery in ${cappedDelay}s: topic="${ctx.topicName}" consumer="${ctx.consumerGroup}" messageId="${ctx.messageId}"`,
  );

  setTimeout(async () => {
    const nextDeliveryCount = ctx.deliveryCount + 1;
    const expiresAt = new Date(
      ctx.createdAt.getTime() + ctx.retentionSeconds * 1000,
    );

    if (Date.now() >= expiresAt.getTime()) {
      console.log(
        `${PREFIX} Message expired, stopping retries: topic="${ctx.topicName}" messageId="${ctx.messageId}"`,
      );
      return;
    }

    if (nextDeliveryCount > DEV_REDELIVERY_MAX_ATTEMPTS) {
      console.log(
        `${PREFIX} Max re-deliveries (${DEV_REDELIVERY_MAX_ATTEMPTS}) reached: topic="${ctx.topicName}" messageId="${ctx.messageId}"`,
      );
      return;
    }

    const metadata: MessageMetadata = {
      messageId: ctx.messageId,
      deliveryCount: nextDeliveryCount,
      createdAt: ctx.createdAt,
      expiresAt,
      topicName: ctx.topicName,
      consumerGroup: ctx.consumerGroup,
      region: ctx.region,
    };

    console.log(
      `${PREFIX} Re-delivering: topic="${ctx.topicName}" consumer="${ctx.consumerGroup}" messageId="${ctx.messageId}" deliveryCount=${nextDeliveryCount}`,
    );

    let succeeded = true;
    let nextRetryAfterS: number | null = null;
    let nextAcknowledged = false;

    try {
      await ctx.handler(ctx.payload, metadata);
    } catch (error) {
      succeeded = false;

      if (ctx.retry) {
        let directive: RetryDirective | void | undefined;
        try {
          directive = ctx.retry(error, metadata);
        } catch (retryErr) {
          console.warn(`${PREFIX} retry handler threw:`, retryErr);
        }

        if (directive && "afterSeconds" in directive) {
          nextRetryAfterS = directive.afterSeconds;
        } else if (directive && "acknowledge" in directive) {
          nextAcknowledged = true;
        }
      }

      if (!nextAcknowledged) {
        console.error(
          `${PREFIX} ${FAIL} Handler error on re-delivery: topic="${ctx.topicName}" messageId="${ctx.messageId}"`,
          error,
        );
      }
    }

    if (succeeded) {
      console.log(
        `${PREFIX} ${OK} Message processed on re-delivery: topic="${ctx.topicName}" consumer="${ctx.consumerGroup}" messageId="${ctx.messageId}"`,
      );
    } else if (nextAcknowledged) {
      console.log(
        `${PREFIX} ${OK} Message acknowledged (will not retry): topic="${ctx.topicName}" consumer="${ctx.consumerGroup}" messageId="${ctx.messageId}"`,
      );
    } else {
      const nextDelay = nextRetryAfterS ?? ctx.defaultRetryDelayS;
      scheduleDevRedelivery(
        { ...ctx, deliveryCount: nextDeliveryCount },
        nextDelay,
      );
    }
  }, cappedDelay * 1000);
}

/**
 * Invoke registered handlers for a topic in dev mode.
 * Constructs a ParsedCallbackV1 and calls coreHandleCallback directly.
 *
 * If no handlers are registered yet (lazy-loaded framework), attempts to
 * dynamically import the route files from vercel.json first.
 */
export function invokeDevHandlers(
  topicName: string,
  messageId: string,
  region: string,
  delaySeconds?: number,
  retentionSeconds?: number,
): void {
  if (delaySeconds && delaySeconds > 0) {
    console.log(
      `${PREFIX} Message sent with delay: topic="${topicName}" messageId="${messageId}" delay=${delaySeconds}s`,
    );
    setTimeout(() => {
      invokeDevHandlers(
        topicName,
        messageId,
        region,
        undefined,
        retentionSeconds,
      );
    }, delaySeconds * 1000);
    return;
  }

  console.log(
    `${PREFIX} Message sent: topic="${topicName}" messageId="${messageId}"`,
  );

  (async () => {
    let handlers = lookupHandlers(topicName);
    let diagnostics: HandlerLoadDiagnostics | null = null;

    if (handlers.length > 0) {
      // Refresh mapped routes to pick up HMR-updated callbacks before invocation.
      await ensureHandlersLoaded(topicName, { refreshRegistered: true });
      handlers = lookupHandlers(topicName);
    } else {
      diagnostics = await ensureHandlersLoaded(topicName);
      handlers = lookupHandlers(topicName);
    }

    if (handlers.length === 0) {
      const matchingRoutes = findMatchingRoutes(topicName);
      if (matchingRoutes.length > 0) {
        const safeDiagnostics = diagnostics ?? {
          triedPorts: collectPrimePorts(),
          listeningPorts: [],
          unavailablePorts: [],
          importFailures: [],
          primeFailures: [],
        };
        console.warn(
          buildNoHandlerWarning(topicName, matchingRoutes, safeDiagnostics),
        );
      } else {
        console.warn(
          `${PREFIX} No registered handler for topic "${topicName}".\n` +
            `Ensure vercel.json has a matching experimentalTriggers entry and ` +
            `the route file calls handleCallback().`,
        );
      }
      return;
    }

    const consumerGroups = handlers.map((h) => h.consumerGroup);
    console.log(
      `${PREFIX} Invoking handlers for topic="${topicName}" messageId="${messageId}" → consumers: [${consumerGroups.join(", ")}]`,
    );

    const effectiveRetention = retentionSeconds ?? DEFAULT_RETENTION_S;

    for (const entry of handlers) {
      let capturedPayload: unknown;
      let capturedCreatedAt: Date = new Date();
      let capturedDeliveryCount = 1;
      let handlerSucceeded = true;
      let retryAfterS: number | null = null;
      let retryAcknowledged = false;

      const wrappedHandler: MessageHandler = async (message, metadata) => {
        capturedPayload = message;
        capturedCreatedAt = metadata.createdAt;
        capturedDeliveryCount = metadata.deliveryCount;
        try {
          await entry.handler(message, metadata);
        } catch (error) {
          handlerSucceeded = false;
          throw error;
        }
      };

      // wrappedRetry observes the user's retry directive for local re-delivery
      // scheduling, then passes it through unchanged to processMessage. This
      // means processMessage will still call changeVisibility on the server,
      // creating dual scheduling (server + local setTimeout). This is safe:
      //
      //  - The server-side reschedule makes the message visible after N seconds,
      //    but no code path in dev mode polls for visible messages. There is no
      //    polling loop, no webhook endpoint, no receive() call. The only thing
      //    that re-invokes the handler is the local setTimeout.
      //
      //  - Deployed consumers cannot claim it either: dev mode omits
      //    deploymentId from all API calls (api-client.ts getSendDeploymentId /
      //    getConsumeDeploymentId return undefined when isDevMode()), so the
      //    receipt handle is not routable to any deployment.
      //
      //  - We intentionally keep the server-side changeVisibility call rather
      //    than suppressing it (e.g. by returning { acknowledge: true }) because
      //    it keeps server-side observability truthful: the message shows as
      //    "pending retry", not "successfully processed".
      //
      //  Known limitation: two local dev processes sharing the same project
      //  credentials could theoretically both claim the same message. This is
      //  an unsupported configuration.
      const wrappedRetry: RetryHandler | undefined = entry.options?.retry
        ? (error, metadata) => {
            const directive = entry.options!.retry!(error, metadata);
            if (directive && "afterSeconds" in directive) {
              retryAfterS = directive.afterSeconds;
            } else if (directive && "acknowledge" in directive) {
              retryAcknowledged = true;
            }
            return directive;
          }
        : undefined;

      const request = {
        queueName: topicName,
        consumerGroup: entry.consumerGroup,
        messageId,
        region,
      };

      const callbackOptions: HandleCallbackOptions = {
        client: entry.client,
        visibilityTimeoutSeconds: entry.options?.visibilityTimeoutSeconds,
        retry: wrappedRetry,
      };

      const consumerDefaultDelay = Math.min(
        findRetryAfterSeconds(topicName, entry.consumerGroup) ??
          DEV_REDELIVERY_DEFAULT_DELAY_S,
        DEV_REDELIVERY_MAX_DELAY_S,
      );

      const buildRedeliveryCtx = (): DevRedeliveryContext => ({
        handler: entry.handler,
        retry: entry.options?.retry,
        payload: capturedPayload,
        topicName,
        consumerGroup: entry.consumerGroup,
        messageId,
        region,
        createdAt: capturedCreatedAt,
        retentionSeconds: effectiveRetention,
        deliveryCount: capturedDeliveryCount,
        defaultRetryDelayS: consumerDefaultDelay,
      });

      try {
        await invokeWithRetry(wrappedHandler, request, callbackOptions);

        if (handlerSucceeded) {
          console.log(
            `${PREFIX} ${OK} Message processed: topic="${topicName}" consumer="${entry.consumerGroup}" messageId="${messageId}"`,
          );
        } else if (retryAcknowledged) {
          console.log(
            `${PREFIX} ${OK} Message acknowledged (will not retry): topic="${topicName}" consumer="${entry.consumerGroup}" messageId="${messageId}"`,
          );
        } else if (retryAfterS !== null) {
          const devDelay = Math.min(retryAfterS, DEV_REDELIVERY_MAX_DELAY_S);
          scheduleDevRedelivery(buildRedeliveryCtx(), devDelay);
        }
      } catch (error) {
        console.error(
          `${PREFIX} ${FAIL} Handler failed: topic="${topicName}" consumer="${entry.consumerGroup}" messageId="${messageId}"`,
          error,
        );
        if (!handlerSucceeded) {
          scheduleDevRedelivery(buildRedeliveryCtx(), consumerDefaultDelay);
        }
      }
    }
  })();
}

// ---------------------------------------------------------------------------
// Test helpers
// ---------------------------------------------------------------------------

function clearDevState(): void {
  const g = globalThis as typeof globalThis & {
    [ROUTE_MAPPINGS_KEY]?: DevRouteMapping[] | null;
    [HANDLER_REGISTRY_KEY]?: HandlerRegistry;
  };
  delete g[ROUTE_MAPPINGS_KEY];
  delete g[HANDLER_REGISTRY_KEY];
}

if (process.env.NODE_ENV === "test" || process.env.VITEST) {
  (globalThis as Record<string, unknown>).__clearDevState = clearDevState;
  (globalThis as Record<string, unknown>).__filePathToConsumerGroup =
    filePathToConsumerGroup;
  (globalThis as Record<string, unknown>).__filePathToUrlPath =
    filePathToUrlPath;
  (globalThis as Record<string, unknown>).__matchesFunctionsPattern =
    matchesFunctionsPattern;
  (globalThis as Record<string, unknown>).__stripSrcPrefix = stripSrcPrefix;
}
